code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, icon } from 'decantr/components';

code.example:
function StepsCard({ title, steps }) {
  const { div, h3, p, span } = tags;

  return Card({},
    Card.Header({},
      div({ class: css('_flex _aic _jcsb') },
        h3({ class: css('_heading5') }, icon('chef-hat'), ` ${title}`),
        span({ class: css('_textsm _fgmuted') }, `${steps.length} steps`)
      )
    ),
    Card.Body({ class: css('_flex _col _gap4') },
      ...steps.map((step, i) =>
        div({ class: css('_flex _gap3') },
          Badge({ variant: 'outline', class: css('_rfull _w[32px] _h[32px] _flex _aic _jcc _shrink0') }, `${i + 1}`),
          div({ class: css('_flex _col _gap1 _flex1') },
            p({}, step.text),
            step.time ? span({ class: css('_textsm _fgmuted') }, icon('timer'), ` ${step.time} min`) : null
          )
        )
      )
    )
  );
}

